1	import { useState } from "react";
2	import { useAuth } from "@/hooks/use-auth";
3	import { useQuery, useMutation } from "@tanstack/react-query";
4	import { apiRequest, queryClient } from "@/lib/queryClient";
5	import ClientLayout from "@/components/layout/ClientLayout";
6	import AdminLayout from "@/components/layout/AdminLayout";
7	import { Card, CardContent } from "@/components/ui/card";
8	import { Button } from "@/components/ui/button";
9	import { Input } from "@/components/ui/input";
10	import { Label } from "@/components/ui/label";
11	import { Textarea } from "@/components/ui/textarea";
12	import { Badge } from "@/components/ui/badge";
13	import { Skeleton } from "@/components/ui/skeleton";
14	import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
15	import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
16	import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
17	import { Switch } from "@/components/ui/switch";
18	import {
19	  Bot, Plus, Trash2, Edit2, Zap, Play, Pause, TrendingUp, MessageSquare,
20	  Clock, Users, CheckCircle2, AlertCircle, ArrowRight, Copy, Check, Sparkles
21	} from "lucide-react";
22	import { useToast } from "@/hooks/use-toast";
23	import { AiRefineButton } from "@/components/ui/AiRefineButton";
24	
25	const MATCH_TYPES = [
26	  { value: "exact", label: "Exact Match", desc: "Keyword must match exactly" },
27	  { value: "contains", label: "Contains", desc: "Message contains keyword" },
28	  { value: "starts_with", label: "Starts With", desc: "Message starts with keyword" },
29	];
30	
31	function TriggerCard({ trigger, onEdit, onDelete, onToggle }: any) {
32	  const matchType = MATCH_TYPES.find(m => m.value === trigger.matchType);
33	  return (
34	    <div className="p-4 border border-card-border bg-card rounded-xl space-y-3 hover:border-primary/30 transition-all">
35	      <div className="flex items-start justify-between gap-3">
36	        <div className="flex-1 min-w-0">
37	          <div className="flex items-center gap-2 mb-1">
38	            <h3 className="text-sm font-semibold text-foreground truncate">{trigger.name}</h3>
39	            {trigger.isActive ? (
40	              <Badge className="bg-green-500/10 text-green-400 border-green-500/30 text-[10px]">
41	                <Play className="w-2.5 h-2.5 mr-1" />Active
42	              </Badge>
43	            ) : (
44	              <Badge className="bg-muted/20 text-muted-foreground border-border text-[10px]">
45	                <Pause className="w-2.5 h-2.5 mr-1" />Paused
46	              </Badge>
47	            )}
48	          </div>
49	          <div className="flex items-center gap-2 text-xs text-muted-foreground">
50	            <span className="px-2 py-0.5 rounded bg-primary/10 text-primary font-mono">{trigger.keyword}</span>
51	            <span>·</span>
52	            <span>{matchType?.label}</span>
53	            <span>·</span>
54	            <span className="flex items-center gap-1">
55	              <Zap className="w-3 h-3" />{trigger.triggerCount || 0} triggers
56	            </span>
57	          </div>
58	        </div>
59	        <div className="flex items-center gap-1">
60	          <Switch checked={trigger.isActive} onCheckedChange={() => onToggle(trigger.id, !trigger.isActive)} />
61	          <button onClick={() => onEdit(trigger)} className="p-1.5 rounded-lg hover:bg-primary/10 text-muted-foreground hover:text-primary transition-colors">
62	            <Edit2 className="w-3.5 h-3.5" />
63	          </button>
64	          <button onClick={() => onDelete(trigger.id)} className="p-1.5 rounded-lg hover:bg-red-500/10 text-muted-foreground hover:text-red-400 transition-colors">
65	            <Trash2 className="w-3.5 h-3.5" />
66	          </button>
67	        </div>
68	      </div>
69	      <div className="p-3 rounded-lg bg-muted/20 border border-border">
70	        <p className="text-xs text-muted-foreground mb-1">Auto-Reply:</p>
71	        <p className="text-xs text-foreground line-clamp-2">{trigger.replyMessage}</p>
72	      </div>
73	    </div>
74	  );
75	}
76	
77	function SequenceCard({ sequence, onEdit, onDelete, onToggle }: any) {
78	  const { data: steps = [] } = useQuery<any[]>({
79	    queryKey: [`/api/dm/sequences/${sequence.id}/steps`],
80	    queryFn: () => fetch(`/api/dm/sequences/${sequence.id}/steps`).then(r => r.json()),
81	  });
82	
83	  const { data: enrollments = [] } = useQuery<any[]>({
84	    queryKey: [`/api/dm/sequences/${sequence.id}/enrollments`],
85	    queryFn: () => fetch(`/api/dm/sequences/${sequence.id}/enrollments`).then(r => r.json()),
86	  });
87	
88	  const activeEnrollments = enrollments.filter((e: any) => !e.completed).length;
89	  const completedEnrollments = enrollments.filter((e: any) => e.completed).length;
90	
91	  return (
92	    <div className="p-4 border border-card-border bg-card rounded-xl space-y-3 hover:border-primary/30 transition-all">
93	      <div className="flex items-start justify-between gap-3">
94	        <div className="flex-1 min-w-0">
95	          <div className="flex items-center gap-2 mb-1">
96	            <h3 className="text-sm font-semibold text-foreground truncate">{sequence.name}</h3>
97	            {sequence.isActive ? (
98	              <Badge className="bg-green-500/10 text-green-400 border-green-500/30 text-[10px]">
99	                <Play className="w-2.5 h-2.5 mr-1" />Active
100	              </Badge>
101	            ) : (
102	              <Badge className="bg-muted/20 text-muted-foreground border-border text-[10px]">
103	                <Pause className="w-2.5 h-2.5 mr-1" />Paused
104	              </Badge>
105	            )}
106	          </div>
107	          {sequence.description && (
108	            <p className="text-xs text-muted-foreground mb-2 line-clamp-1">{sequence.description}</p>
109	          )}
110	          <div className="flex items-center gap-3 text-xs text-muted-foreground">
111	            <span className="flex items-center gap-1">
112	              <MessageSquare className="w-3 h-3" />{steps.length} steps
113	            </span>
114	            <span className="flex items-center gap-1">
115	              <Users className="w-3 h-3" />{activeEnrollments} active
116	            </span>
117	            <span className="flex items-center gap-1">
118	              <CheckCircle2 className="w-3 h-3" />{completedEnrollments} completed
119	            </span>
120	          </div>
121	        </div>
122	        <div className="flex items-center gap-1">
123	          <Switch checked={sequence.isActive} onCheckedChange={() => onToggle(sequence.id, !sequence.isActive)} />
124	          <button onClick={() => onEdit(sequence)} className="p-1.5 rounded-lg hover:bg-primary/10 text-muted-foreground hover:text-primary transition-colors">
125	            <Edit2 className="w-3.5 h-3.5" />
126	          </button>
127	          <button onClick={() => onDelete(sequence.id)} className="p-1.5 rounded-lg hover:bg-red-500/10 text-muted-foreground hover:text-red-400 transition-colors">
128	            <Trash2 className="w-3.5 h-3.5" />
129	          </button>
130	        </div>
131	      </div>
132	      {steps.length > 0 && (
133	        <div className="flex items-center gap-2 overflow-x-auto pb-2">
134	          {steps.slice(0, 3).map((step: any, i: number) => (
135	            <div key={step.id} className="flex items-center gap-2 flex-shrink-0">
136	              <div className="px-2 py-1 rounded bg-primary/10 border border-primary/20 text-[10px] text-primary font-medium">
137	                {step.delayDays === 0 ? "Instant" : `Day ${step.delayDays}`}
138	              </div>
139	              {i < Math.min(steps.length - 1, 2) && <ArrowRight className="w-3 h-3 text-muted-foreground" />}
140	            </div>
141	          ))}
142	          {steps.length > 3 && (
143	            <span className="text-[10px] text-muted-foreground">+{steps.length - 3} more</span>
144	          )}
145	        </div>
146	      )}
147	    </div>
148	  );
149	}
150	
151	function TriggerDialog({ open, onClose, existing, clientId }: any) {
152	  const { toast } = useToast();
153	  const [form, setForm] = useState({
154	    name: existing?.name || "",
155	    keyword: existing?.keyword || "",
156	    matchType: existing?.matchType || "contains",
157	    replyMessage: existing?.replyMessage || "",
158	    isActive: existing?.isActive ?? true,
159	  });
160	
161	  const createMutation = useMutation({
162	    mutationFn: (data: any) => apiRequest("POST", "/api/dm/triggers", { ...data, userId: clientId }),
163	    onSuccess: () => {
164	      queryClient.invalidateQueries({ queryKey: ["/api/dm/triggers"] });
165	      toast({ title: "Trigger created!" });
166	      onClose();
167	    },
168	    onError: (e: any) => toast({ title: "Error", description: e.message, variant: "destructive" }),
169	  });
170	
171	  const updateMutation = useMutation({
172	    mutationFn: (data: any) => apiRequest("PATCH", `/api/dm/triggers/${existing?.id}`, data),
173	    onSuccess: () => {
174	      queryClient.invalidateQueries({ queryKey: ["/api/dm/triggers"] });
175	      toast({ title: "Trigger updated!" });
176	      onClose();
177	    },
178	    onError: (e: any) => toast({ title: "Error", description: e.message, variant: "destructive" }),
179	  });
180	
181	  const submit = () => {
182	    if (!form.name.trim()) return toast({ title: "Name required", variant: "destructive" });
183	    if (!form.keyword.trim()) return toast({ title: "Keyword required", variant: "destructive" });
184	    if (!form.replyMessage.trim()) return toast({ title: "Reply message required", variant: "destructive" });
185	    
186	    const payload = {
187	      name: form.name.trim(),
188	      keyword: form.keyword.trim().toLowerCase(),
189	      matchType: form.matchType,
190	      replyMessage: form.replyMessage.trim(),
191	      isActive: form.isActive,
192	    };
193	    
194	    if (existing) updateMutation.mutate(payload);
195	    else createMutation.mutate(payload);
196	  };
197	
198	  const isPending = createMutation.isPending || updateMutation.isPending;
199	
200	  return (
201	    <Dialog open={open} onOpenChange={v => !v && onClose()}>
202	      <DialogContent className="max-w-lg">
203	        <DialogHeader>
204	          <DialogTitle>{existing ? "Edit Trigger" : "Create Auto-Reply Trigger"}</DialogTitle>
205	        </DialogHeader>
206	        <div className="space-y-4 py-2">
207	          <div>
208	            <Label className="text-xs text-muted-foreground">Trigger Name *</Label>
209	            <Input value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} placeholder="e.g. Welcome Message" className="mt-1" />
210	          </div>
211	          <div className="grid grid-cols-2 gap-3">
212	            <div>
213	              <Label className="text-xs text-muted-foreground">Keyword *</Label>
214	              <Input value={form.keyword} onChange={e => setForm(f => ({ ...f, keyword: e.target.value }))} placeholder="e.g. hello" className="mt-1" />
215	            </div>
216	            <div>
217	              <Label className="text-xs text-muted-foreground">Match Type</Label>
218	              <Select value={form.matchType} onValueChange={v => setForm(f => ({ ...f, matchType: v }))}>
219	                <SelectTrigger className="mt-1">
220	                  <SelectValue />
221	                </SelectTrigger>
222	                <SelectContent>
223	                  {MATCH_TYPES.map(m => (
224	                    <SelectItem key={m.value} value={m.value}>
225	                      <div>
226	                        <p className="text-xs font-medium">{m.label}</p>
227	                        <p className="text-[10px] text-muted-foreground">{m.desc}</p>
228	                      </div>
229	                    </SelectItem>
230	                  ))}
231	                </SelectContent>
232	              </Select>
233	            </div>
234	          </div>
235	          <div>
236	            <Label className="text-xs text-muted-foreground">Auto-Reply Message *</Label>
237	            <Textarea value={form.replyMessage} onChange={e => setForm(f => ({ ...f, replyMessage: e.target.value }))} placeholder="Hey! Thanks for reaching out..." rows={4} className="mt-1 resize-none" />
238	            <AiRefineButton text={form.replyMessage} onAccept={v => setForm(f => ({ ...f, replyMessage: v }))} context="Instagram DM auto-reply message" />
239	          </div>
240	          <div className="flex items-center justify-between p-3 rounded-lg bg-muted/20 border border-border">
241	            <div>
242	              <p className="text-xs font-medium text-foreground">Active</p>
243	              <p className="text-[10px] text-muted-foreground">Trigger will auto-reply when active</p>
244	            </div>
245	            <Switch checked={form.isActive} onCheckedChange={v => setForm(f => ({ ...f, isActive: v }))} />
246	          </div>
247	        </div>
248	        <DialogFooter>
249	          <Button variant="outline" onClick={onClose}>Cancel</Button>
250	          <Button onClick={submit} disabled={isPending}>
251	            {isPending ? "Saving..." : existing ? "Save Changes" : "Create Trigger"}
252	          </Button>
253	        </DialogFooter>
254	      </DialogContent>
255	    </Dialog>
256	  );
257	}
258	
259	function SequenceDialog({ open, onClose, existing, clientId }: any) {
260	  const { toast } = useToast();
261	  const [form, setForm] = useState({
262	    name: existing?.name || "",
263	    description: existing?.description || "",
264	    isActive: existing?.isActive ?? true,
265	  });
266	
267	  const createMutation = useMutation({
268	    mutationFn: (data: any) => apiRequest("POST", "/api/dm/sequences", { ...data, userId: clientId }),
269	    onSuccess: () => {
270	      queryClient.invalidateQueries({ queryKey: ["/api/dm/sequences"] });
271	      toast({ title: "Sequence created!" });
272	      onClose();
273	    },
274	    onError: (e: any) => toast({ title: "Error", description: e.message, variant: "destructive" }),
275	  });
276	
277	  const updateMutation = useMutation({
278	    mutationFn: (data: any) => apiRequest("PATCH", `/api/dm/sequences/${existing?.id}`, data),
279	    onSuccess: () => {
280	      queryClient.invalidateQueries({ queryKey: ["/api/dm/sequences"] });
281	      toast({ title: "Sequence updated!" });
282	      onClose();
283	    },
284	    onError: (e: any) => toast({ title: "Error", description: e.message, variant: "destructive" }),
285	  });
286	
287	  const submit = () => {
288	    if (!form.name.trim()) return toast({ title: "Name required", variant: "destructive" });
289	    
290	    const payload = {
291	      name: form.name.trim(),
292	      description: form.description.trim() || null,
293	      isActive: form.isActive,
294	    };
295	    
296	    if (existing) updateMutation.mutate(payload);
297	    else createMutation.mutate(payload);
298	  };
299	
300	  const isPending = createMutation.isPending || updateMutation.isPending;
301	
302	  return (
303	    <Dialog open={open} onOpenChange={v => !v && onClose()}>
304	      <DialogContent className="max-w-md">
305	        <DialogHeader>
306	          <DialogTitle>{existing ? "Edit Sequence" : "Create DM Sequence"}</DialogTitle>
307	        </DialogHeader>
308	        <div className="space-y-4 py-2">
309	          <div>
310	            <Label className="text-xs text-muted-foreground">Sequence Name *</Label>
311	            <Input value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} placeholder="e.g. Welcome Series" className="mt-1" />
312	          </div>
313	          <div>
314	            <Label className="text-xs text-muted-foreground">Description</Label>
315	            <Textarea value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} placeholder="What is this sequence for?" rows={2} className="mt-1 resize-none" />
316	          </div>
317	          <div className="flex items-center justify-between p-3 rounded-lg bg-muted/20 border border-border">
318	            <div>
319	              <p className="text-xs font-medium text-foreground">Active</p>
320	              <p className="text-[10px] text-muted-foreground">New enrollments will be processed</p>
321	            </div>
322	            <Switch checked={form.isActive} onCheckedChange={v => setForm(f => ({ ...f, isActive: v }))} />
323	          </div>
324	        </div>
325	        <DialogFooter>
326	          <Button variant="outline" onClick={onClose}>Cancel</Button>
327	          <Button onClick={submit} disabled={isPending}>
328	            {isPending ? "Saving..." : existing ? "Save Changes" : "Create Sequence"}
329	          </Button>
330	        </DialogFooter>
331	      </DialogContent>
332	    </Dialog>
333	  );
334	}
