336	export default function DMAutomation({ useAdmin = false }: { useAdmin?: boolean }) {
337	  const { user } = useAuth();
338	  const { toast } = useToast();
339	  const Layout = useAdmin ? AdminLayout : ClientLayout;
340	  const isAdmin = useAdmin || user?.role === "admin";
341	
342	  const [triggerDialogOpen, setTriggerDialogOpen] = useState(false);
343	  const [editingTrigger, setEditingTrigger] = useState<any>(null);
344	  const [sequenceDialogOpen, setSequenceDialogOpen] = useState(false);
345	  const [editingSequence, setEditingSequence] = useState<any>(null);
346	
347	  const activeClientId = user?.id || "";
348	
349	  const { data: triggers = [], isLoading: triggersLoading } = useQuery<any[]>({
350	    queryKey: ["/api/dm/triggers", activeClientId],
351	    queryFn: () => fetch(`/api/dm/triggers${activeClientId ? `?userId=${activeClientId}` : ""}`).then(r => r.json()),
352	  });
353	
354	  const { data: sequences = [], isLoading: sequencesLoading } = useQuery<any[]>({
355	    queryKey: ["/api/dm/sequences", activeClientId],
356	    queryFn: () => fetch(`/api/dm/sequences${activeClientId ? `?userId=${activeClientId}` : ""}`).then(r => r.json()),
357	  });
358	
359	  const deleteTriggerMutation = useMutation({
360	    mutationFn: (id: string) => apiRequest("DELETE", `/api/dm/triggers/${id}`),
361	    onSuccess: () => {
362	      queryClient.invalidateQueries({ queryKey: ["/api/dm/triggers"] });
363	      toast({ title: "Trigger deleted" });
364	    },
365	  });
366	
367	  const toggleTriggerMutation = useMutation({
368	    mutationFn: ({ id, isActive }: any) => apiRequest("PATCH", `/api/dm/triggers/${id}`, { isActive }),
369	    onSuccess: () => queryClient.invalidateQueries({ queryKey: ["/api/dm/triggers"] }),
370	  });
371	
372	  const deleteSequenceMutation = useMutation({
373	    mutationFn: (id: string) => apiRequest("DELETE", `/api/dm/sequences/${id}`),
374	    onSuccess: () => {
375	      queryClient.invalidateQueries({ queryKey: ["/api/dm/sequences"] });
376	      toast({ title: "Sequence deleted" });
377	    },
378	  });
379	
380	  const toggleSequenceMutation = useMutation({
381	    mutationFn: ({ id, isActive }: any) => apiRequest("PATCH", `/api/dm/sequences/${id}`, { isActive }),
382	    onSuccess: () => queryClient.invalidateQueries({ queryKey: ["/api/dm/sequences"] }),
383	  });
384	
385	  const activeTriggers = triggers.filter(t => t.isActive).length;
386	  const activeSequences = sequences.filter(s => s.isActive).length;
387	  const totalTriggerCount = triggers.reduce((sum, t) => sum + (t.triggerCount || 0), 0);
388	
389	  return (
390	    <Layout>
391	      <div className="p-6 space-y-6 max-w-7xl mx-auto">
392	        <div className="flex items-center justify-between gap-4 flex-wrap">
393	          <div className="flex items-center gap-3">
394	            <div className="w-10 h-10 bg-primary/10 rounded-xl flex items-center justify-center">
395	              <Bot className="w-5 h-5 text-primary" />
396	            </div>
397	            <div>
398	              <h1 className="text-xl font-bold text-foreground">DM Automation</h1>
399	              <p className="text-xs text-muted-foreground">Auto-replies & drip sequences</p>
400	            </div>
401	          </div>
402	        </div>
403	
404	        {/* Stats */}
405	        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
406	          {[
407	            { label: "Active Triggers", val: activeTriggers, color: "text-green-400", bg: "bg-green-500/10 border-green-500/20", icon: Zap },
408	            { label: "Active Sequences", val: activeSequences, color: "text-blue-400", bg: "bg-blue-500/10 border-blue-500/20", icon: MessageSquare },
409	            { label: "Total Triggers", val: totalTriggerCount, color: "text-amber-400", bg: "bg-amber-500/10 border-amber-500/20", icon: TrendingUp },
410	            { label: "Total Automations", val: triggers.length + sequences.length, color: "text-purple-400", bg: "bg-purple-500/10 border-purple-500/20", icon: Sparkles },
411	          ].map(s => {
412	            const Icon = s.icon;
413	            return (
414	              <div key={s.label} className={`border rounded-xl p-3 ${s.bg}`}>
415	                <div className="flex items-center gap-2 mb-1">
416	                  <Icon className={`w-3.5 h-3.5 ${s.color}`} />
417	                  <p className={`text-xl font-bold ${s.color}`}>{s.val}</p>
418	                </div>
419	                <p className="text-[10px] text-muted-foreground">{s.label}</p>
420	              </div>
421	            );
422	          })}
423	        </div>
424	
425	        <Tabs defaultValue="triggers">
426	          <TabsList>
427	            <TabsTrigger value="triggers" className="gap-1.5 text-xs">
428	              <Zap className="w-3.5 h-3.5" />Auto-Replies
429	            </TabsTrigger>
430	            <TabsTrigger value="sequences" className="gap-1.5 text-xs">
431	              <MessageSquare className="w-3.5 h-3.5" />Sequences
432	            </TabsTrigger>
433	          </TabsList>
434	
435	          {/* Triggers Tab */}
436	          <TabsContent value="triggers" className="mt-4 space-y-4">
437	            <div className="flex items-center justify-between">
438	              <p className="text-sm text-muted-foreground">Automatically reply when someone sends a keyword</p>
439	              <Button onClick={() => { setEditingTrigger(null); setTriggerDialogOpen(true); }} className="gap-2 h-9 text-sm">
440	                <Plus className="w-4 h-4" /> New Trigger
441	              </Button>
442	            </div>
443	
444	            {triggersLoading ? (
445	              <div className="space-y-3">{[1, 2, 3].map(i => <Skeleton key={i} className="h-32 rounded-xl" />)}</div>
446	            ) : triggers.length === 0 ? (
447	              <div className="text-center py-16 border border-dashed border-border rounded-2xl">
448	                <Zap className="w-10 h-10 text-muted-foreground mx-auto mb-3 opacity-30" />
449	                <p className="text-sm text-muted-foreground mb-4">No auto-reply triggers yet</p>
450	                <Button onClick={() => { setEditingTrigger(null); setTriggerDialogOpen(true); }} className="gap-2">
451	                  <Plus className="w-4 h-4" /> Create Your First Trigger
452	                </Button>
453	              </div>
454	            ) : (
455	              <div className="grid gap-3">
456	                {triggers.map(trigger => (
457	                  <TriggerCard
458	                    key={trigger.id}
459	                    trigger={trigger}
460	                    onEdit={(t: any) => { setEditingTrigger(t); setTriggerDialogOpen(true); }}
461	                    onDelete={(id: string) => { if (confirm("Delete this trigger?")) deleteTriggerMutation.mutate(id); }}
462	                    onToggle={(id: string, isActive: boolean) => toggleTriggerMutation.mutate({ id, isActive })}
463	                  />
464	                ))}
465	              </div>
466	            )}
467	          </TabsContent>
468	
469	          {/* Sequences Tab */}
