        {/* Main Tabs */}
        <Tabs defaultValue="triggers">
          <TabsList className="flex-wrap">
            <TabsTrigger value="triggers"      className="gap-1.5 text-xs"><Zap className="w-3.5 h-3.5" />Auto-Replies</TabsTrigger>
